{!REQUIRESCRIPT("/soap/ajax/33.0/apex.js")}

var result = sforce.connection.query("SELECT id,IP_State__c,IP_Status__c,IP_ErrorReason__c,IP_LinkField4__c,IP_LinkField2__c FROM IP_BatchLine__c WHERE IP_BatchHeader__c = '{!Batch_header__c.Id }' and IP_Status__c ='Errored' Limit 200");

var result1 = sforce.connection.query("SELECT id,IP_BatchType__c FROM Batch_header__c WHERE id = '{!Batch_header__c.Id }' and IP_Status__c ='Errored'");


records = result.getArray("records");
records1 = result1.getArray("records");

var type = '{!Batch_header__c.IP_BatchType__c}';

var updatecertRecord = new Array();
var idsForDeletion = [];
for (i=0; i < records.length ; i++)
{
var child = records[i];
child.IP_Status__c="Open";
child.IP_ErrorReason__c=null;
updatecertRecord.push(child);
if((records[i].IP_LinkField4__c != null || records[i].IP_LinkField4__c != '') && (records[i].IP_LinkField2__c == null || records[i].IP_LinkField2__c == ''))
idsForDeletion.push(records[i].IP_LinkField4__c);
}
result = sforce.connection.update(updatecertRecord);
if(type == 'Capita')
{
if(idsForDeletion[0] != null && idsForDeletion.length>=1)
{

sforce.connection.deleteIds(idsForDeletion);
}
var apexClassArray= sforce.connection.query("SELECT Id FROM ApexClass WHERE Name ='CapitaBatchHeaderclass'");

recordsclassid= apexClassArray.getArray("records");

var checkBatchRunningRecords= sforce.connection.query("SELECT ApexClassId, status FROM AsyncApexJob WHERE ApexClassId ='"+recordsclassid[0].Id+"' AND Status NOT IN ('Completed','Aborted','Failed')");

records= checkBatchRunningRecords.getArray("records");

if(records.length>0){
window.alert("The batch job is currently executing. Please wait for it to complete.");
}
else{
window.alert('The Integration batch job has started.');
var batchid=sforce.apex.execute("WebserviceclassCapita","Capitabatch",{});

}
}
